scwin.openPopup = function(data){
    return new Promise((resolve) => {

        let opts = {
            id: "ozReportPopup_" + new Date().getTime(), // 충돌 방지 (중요)
            popupName: "오즈 리포트",
            modal: false,
            type: "browserPopup",
            width: 1000,
            height: 600,
            title: "오즈 리포트",

            closeAction: function() {
                resolve();
            }
        };

        $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
    });
};

