scwin.f_downBillPrint = async function() {
    let options = {
        fileName : "BILL 내역.xlsx",
        sheetName : "BILL 내역"
    }

    let grdObj = gr_billPrint;

    let infoArr = {};

    if(ds_mobileLog.getTotalRow() == 0) {
        $c.win.alert(MSG_CM_WRN_002);
    } else {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            $c.data.downloadGridViewExcel(grdObj, options, infoArr)
        }
    }
}


